package com.example.oms.controller;
import com.example.oms.entity.*; import com.example.oms.repository.*; import jakarta.persistence.EntityNotFoundException; import lombok.RequiredArgsConstructor; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/stock") @RequiredArgsConstructor
public class StockController { private final ProductRepository products; private final StockHistoryRepository history; @GetMapping("/history") List<StockHistory> history(){ return history.findAll(); } @PatchMapping("/{productId}") Product adjust(@PathVariable Long productId, @RequestParam StockHistory.StockChangeType type, @RequestParam int quantity, @RequestParam(required=false) String note){ Product p=products.findById(productId).orElseThrow(() -> new EntityNotFoundException("Product not found")); int updated= type==StockHistory.StockChangeType.REMOVE ? p.getStockQty()-quantity : type==StockHistory.StockChangeType.ADD ? p.getStockQty()+quantity : quantity; p.setStockQty(updated); history.save(StockHistory.builder().product(p).changeType(type).quantity(quantity).note(note).build()); return products.save(p); } }
